function loadSchema(schemaName) {
  if (schemaCache[schemaName]) return schemaCache[schemaName];
  
  const schemaPath = resolve(SCHEMA_DIR, schemaName);
  if (!existsSync(schemaPath)) {
    throw new Error(`Schema not found: ${schemaPath}`);
  }
  
  const content = readFileSync(schemaPath, 'utf-8');
  const schema = JSON.parse(content);
  schemaCache[schemaName] = schema;
  return schema;
}

// ─── Ajv Setup ─────────────────────────────────────────────────────

let ajv = null;

/**
 * Get or create an Ajv instance.
 */

async function getAjv() {
  if (ajv) return ajv;
  
  try {
    const Ajv = (await import('ajv')).default;
    const addFormats = (await import('ajv-formats')).default;
    
    ajv = new Ajv({
      allErrors: true,
      verbose: true,
      strict: false,
      validateSchema: false
    });
    
    addFormats(ajv);
    
    // Add custom USX format validators
    ajv.addFormat('usx-template', {
      type: 'string',
      validate: (str) => !str || /^[^{}]*(\{\{[^}]+\}\}[^{}]*)*$/.test(str)
    });
    
    ajv.addFormat('css-variable', {
      type: 'string',
      validate: (str) => !str || /^--[a-zA-Z][a-zA-Z0-9-]*$/.test(str)
    });
    
    ajv.addFormat('hex-color', {
      type: 'string',
      validate: (str) => !str || /^#[0-9a-fA-F]{3,8}$/.test(str)
    });
    
    ajv.addFormat('semver', {
      type: 'string',
      validate: (str) => !str || /^\d+\.\d+\.\d+/.test(str)
    });
    
  } catch (err) {
    console.warn('⚠️  Ajv not available, falling back to basic validation:', err.message);
    ajv = null;
  }
  
  return ajv;
}

// ─── Validation Functions ──────────────────────────────────────────

/**
 * Validate a complete USX bundle against the bundle schema.
 * @param {Object} bundle - USX bundle object
 * @param {Object} [options] - Validation options
 * @param {boolean} [options.strict=false] - Strict mode (fail on warnings)
 * @param {boolean} [options.validateSections=true] - Also validate individual sections
 * @returns {Object} Validation result
 */

export async function validateBundle(bundle, options = {}) {
  const { strict = false, validateSections = true } = options;
  const errors = [];
  const warnings = [];
  
  // Basic structure checks
  if (!bundle || typeof bundle !== 'object') {
    return { valid: false, errors: ['Bundle must be a JSON object'], warnings: [] };
  }
  
  // Required top-level fields
  const requiredFields = ['version', 'id', 'name', 'lens', 'skin', 'layout'];
  for (const field of requiredFields) {
    if (bundle[field] === undefined || bundle[field] === null) {
      errors.push(`Missing required field: "${field}"`);
    }
  }
  
  // Version check
  if (bundle.version && !/^\d+\.\d+\.\d+/.test(bundle.version)) {
    warnings.push(`Version "${bundle.version}" is not valid semver`);
  }
  
  // ID format
  if (bundle.id && !/^[a-zA-Z0-9_-]+$/.test(bundle.id)) {
    warnings.push(`ID "${bundle.id}" should only contain alphanumeric, hyphens, and underscores`);
  }
  
  // Schema validation (if Ajv is available)
  const validator = await getAjv();
  if (validator) {
    try {
      const bundleSchema = loadSchema('bundle.schema.json');
      const validate = validator.compile(bundleSchema);
      const valid = validate(bundle);
      
      if (!valid) {
        for (const err of validate.errors) {
          errors.push(`[Schema] ${err.instancePath || '(root)'} ${err.message}`);
        }
      }
    } catch (err) {
      warnings.push(`Schema validation error: ${err.message}`);
    }
  }
  
  // Validate individual sections
  if (validateSections) {
    if (bundle.lens) {
      const lensResult = await validateSection(bundle.lens, 'lens');
      errors.push(...lensResult.errors);
      warnings.push(...lensResult.warnings);
    }
    
    if (bundle.skin) {
      const skinResult = await validateSection(bundle.skin, 'skin');
      errors.push(...skinResult.errors);
      warnings.push(...skinResult.warnings);
    }
    
    if (bundle.layout) {
      const layoutResult = await validateSection(bundle.layout, 'layout');
      errors.push(...layoutResult.errors);
      warnings.push(...layoutResult.warnings);
    }
  }
  
  // Cross-section validation
  if (bundle.lens && bundle.layout) {
    const crossErrors = validateCrossSection(bundle);
    errors.push(...crossErrors);
  }
  
  return {
    valid: errors.length === 0 && (strict ? warnings.length === 0 : true),
    errors,
    warnings,
    total_errors: errors.length,
    total_warnings: warnings.length
  };
}

/**
 * Validate a single USX section against its schema.
 * @param {Object} section - Section object (lens, skin, or layout)
 * @param {string} sectionName - Section name ('lens', 'skin', 'layout')
 * @returns {Object} Validation result
 */

export async function validateSection(section, sectionName) {
  const errors = [];
  const warnings = [];
  
  if (!section || typeof section !== 'object') {
    return { errors: [`${sectionName} must be a JSON object`], warnings: [] };
  }
  
  // Version check
  if (!section.version) {
    warnings.push(`${sectionName} is missing "version" field`);
  }
  
  // Section-specific validation
  switch (sectionName) {
    case 'lens':
      validateLens(section, errors, warnings);
      break;
    case 'skin':
      validateSkin(section, errors, warnings);
      break;
    case 'layout':
      validateLayout(section, errors, warnings);
      break;
  }
  
  // Schema validation (if Ajv is available)
  const validator = await getAjv();
  if (validator) {
    const schemaName = `${sectionName}.schema.json`;
    try {
      const schema = loadSchema(schemaName);
      const validate = validator.compile(schema);
      const valid = validate(section);
      
      if (!valid) {
        for (const err of validate.errors) {
          errors.push(`[${sectionName}] ${err.instancePath || '(root)'} ${err.message}`);
        }
      }
    } catch (err) {
      warnings.push(`[${sectionName}] Schema validation error: ${err.message}`);
    }
  }
  
  return { errors, warnings };
}

// ─── Section Validators ────────────────────────────────────────────

/**
 * Validate LENS section.
 */

function validateLens(lens, errors, warnings) {
  // Variables
  if (lens.variables) {
    if (typeof lens.variables !== 'object') {
      errors.push('lens.variables must be an object');
    } else {
      for (const [name, variable] of Object.entries(lens.variables)) {
        if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(name)) {
          warnings.push(`Variable name "${name}" may not be valid in all contexts`);
        }
        if (variable.type && !['string', 'number', 'boolean', 'object', 'array'].includes(variable.type)) {
          warnings.push(`Variable "${name}" has unknown type "${variable.type}"`);
        }
      }
    }
  }
  
  // Runtime
  if (lens.runtime) {
    if (lens.runtime.connection_status && !['connected', 'disconnected', 'connecting', 'error'].includes(lens.runtime.connection_status)) {
      warnings.push(`Unknown connection_status: "${lens.runtime.connection_status}"`);
    }
  }
}

/**
 * Validate SKIN section.
 */

function validateSkin(skin, errors, warnings) {
  // Framework
  if (skin.framework && !['tailwind', 'bootstrap', 'custom', 'none'].includes(skin.framework)) {
    warnings.push(`Unknown framework: "${skin.framework}"`);
  }
  
  // Colors
  if (skin.colors) {
    if (typeof skin.colors !== 'object') {
      errors.push('skin.colors must be an object');
    } else {
      for (const [name, color] of Object.entries(skin.colors)) {
        if (!color.light) {
          warnings.push(`Color "${name}" is missing "light" value`);
        }
        if (color.light && !/^#[0-9a-fA-F]{3,8}$/.test(color.light)) {
          warnings.push(`Color "${name}" light value "${color.light}" is not a valid hex color`);
        }
        if (color.dark && !/^#[0-9a-fA-F]{3,8}$/.test(color.dark)) {
          warnings.push(`Color "${name}" dark value "${color.dark}" is not a valid hex color`);
        }
      }
    }
  }
  
  // Typography
  if (skin.typography) {
    for (const [name, type] of Object.entries(skin.typography)) {
      if (!type.font_family) {
        warnings.push(`Typography "${name}" is missing "font_family"`);
      }
      if (!type.font_size) {
        warnings.push(`Typography "${name}" is missing "font_size"`);
      }
    }
  }
  
  // Components
  if (skin.components) {
    for (const [name, component] of Object.entries(skin.components)) {
      if (!component.base && !component.variants) {
        warnings.push(`Component "${name}" has no "base" or "variants"`);
      }
    }
  }
}

/**
 * Validate Layout section.
 */

function validateLayout(layout, errors, warnings) {
  // Type
  if (layout.type && !['surface', 'widget', 'page', 'modal', 'panel'].includes(layout.type)) {
    warnings.push(`Unknown layout type: "${layout.type}"`);
  }
  
  // Root widget
  if (layout.root) {
    validateWidget(layout.root, errors, warnings, 'root');
  }
  
  // Widgets array
  if (layout.widgets) {
    if (!Array.isArray(layout.widgets)) {
      errors.push('layout.widgets must be an array');
    } else {
      layout.widgets.forEach((widget, i) => {
        validateWidget(widget, errors, warnings, `widgets[${i}]`);
      });
    }
  }
}

/**
 * Validate a single widget node.
 */
function validateWidget(widget, errors, warnings, path) {
  if (!widget || typeof widget !== 'object') {
    errors.push(`${path}: widget must be an object`);
    return;
  }
  
  // Required fields
  if (!widget.id) {
    errors.push(`${path}: widget is missing "id"`);
  }
  
  if (!widget.type) {
    errors.push(`${path}: widget is missing "type"`);
  } else {
    const validTypes = [
      'container', 'text', 'heading', 'button', 'input', 'image',
      'icon', 'divider', 'card', 'list', 'table', 'code_block',
      'quote', 'callout', 'todo', 'toggle', 'iframe', 'custom'
    ];
    if (!validTypes.includes(widget.type)) {
      warnings.push(`${path}: unknown widget type "${widget.type}"`);
    }
  }
  
  // Content
  if (widget.content && typeof widget.content !== 'object') {
    warnings.push(`${path}.content should be an object`);
  }
  
  // Children
  if (widget.children) {
    if (!Array.isArray(widget.children)) {
      errors.push(`${path}.children must be an array`);
    } else {
      widget.children.forEach((child, i) => {
        validateWidget(child, errors, warnings, `${path}.children[${i}]`);
      });
    }
  }
  
  // Repeat
  if (widget.repeat) {
    if (!widget.repeat.source) {
      warnings.push(`${path}.repeat is missing "source"`);
    }
    if (!widget.repeat.as) {
      warnings.push(`${path}.repeat is missing "as"`);
    }
  }
}

// ─── Cross-Section Validation ──────────────────────────────────────

/**
 * Validate cross-section references.
 */

function validateCrossSection(bundle) {
  const errors = [];
  const { lens, layout } = bundle;
  
  // Check template variable references in layout
  const templateRegex = /\{\{([^}]+)\}\}/g;
  
  function checkTemplates(obj, path) {
    if (!obj || typeof obj !== 'object') return;
    
    if (typeof obj === 'string') {
      let match;
      while ((match = templateRegex.exec(obj)) !== null) {
        const ref = match[1].trim();
        const keys = ref.split('.');
        let current = lens;
        let found = true;
        for (const key of keys) {
          if (current && current[key] !== undefined) {
            current = current[key];
          } else {
            found = false;
            break;
          }
        }
        if (!found) {
          errors.push(`Template reference "${ref}" in ${path} does not exist in LENS`);
        }
      }
    }
    
    if (Array.isArray(obj)) {
      obj.forEach((item, i) => checkTemplates(item, `${path}[${i}]`));
    } else if (typeof obj === 'object') {
      for (const [key, value] of Object.entries(obj)) {
        if (key !== 'raw_json') {
          checkTemplates(value, `${path}.${key}`);
        }
      }
    }
  }
  
  checkTemplates(layout, 'layout');
  
  return errors;
}

// ─── Utility Functions ─────────────────────────────────────────────

/**
 * Validate a bundle file from disk.
 * @param {string} filePath - Path to .usx file
 * @param {Object} [options] - Validation options
 * @returns {Object} Validation result
 */

export async function validateBundleFile(filePath, options = {}) {
  const resolvedPath = resolve(filePath);
  
  if (!existsSync(resolvedPath)) {
    return { valid: false, errors: [`File not found: ${resolvedPath}`], warnings: [] };
  }
  
  try {
    const content = readFileSync(resolvedPath, 'utf-8');
    const bundle = JSON.parse(content);
    return await validateBundle(bundle, options);
  } catch (err) {
    return {
      valid: false,
      errors: [`Failed to parse bundle: ${err.message}`],
      warnings: []
    };
  }
}

/**
 * Format validation results as a human-readable string.
 * @param {Object} result - Validation result
 * @returns {string} Formatted output
 */

export function formatValidationResult(result) {
  const lines = [];
  
  if (result.valid) {
    lines.push('✅ Bundle is valid');
  } else {
    lines.push('❌ Bundle has errors');
  }
  
  if (result.errors.length > 0) {
    lines.push(`\nErrors (${result.errors.length}):`);
    for (const err of result.errors) {
      lines.push(`  ❌ ${err}`);
    }
  }
  
  if (result.warnings.length > 0) {
    lines.push(`\nWarnings (${result.warnings.length}):`);
    for (const warn of result.warnings) {
      lines.push(`  ⚠️  ${warn}`);
    }
  }
  
  lines.push(`\n${result.total_errors} errors, ${result.total_warnings} warnings`);
  
  return lines.join('\n');
}

